SELECT COUNT(*) AS total_ties
FROM world_series
WHERE ties > 0;

SELECT year_id, COUNT(game_id) AS total_games
FROM world_series
GROUP BY year_id;

SELECT team_id_winner, SUM(wins) AS total_triumphs
FROM world_series
GROUP BY team_id_winner;

SELECT game_location 
FROM world_series 
WHERE game_id = 0;

SELECT year_id, team_id_winner
FROM world_series
ORDER BY year_id ASC;
